eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   ARTICLES: () => (/* binding */ ARTICLES),\n/* harmony export */   CATEGORIES: () => (/* binding */ CATEGORIES),\n/* harmony export */   formatDate: () => (/* binding */ formatDate),\n/* harmony export */   getAllArticles: () => (/* binding */ getAllArticles),\n/* harmony export */   getArticleBySlug: () => (/* binding */ getArticleBySlug),\n/* harmony export */   getArticlesByCategory: () => (/* binding */ getArticlesByCategory)\n/* harmony export */ });\n// SAFE MAGAZINE記事データのユーティリティ\n// カテゴリーの定義\nconst CATEGORIES = {\n    \"accident-news\": {\n        label: \"事故ニュース\",\n        color: \"#EF4444\",\n        bgColor: \"bg-red-500\",\n        textColor: \"text-red-600\",\n        bgLight: \"bg-red-50\",\n        icon: \"AlertTriangle\"\n    },\n    \"danger-ranking\": {\n        label: \"危険度情報\",\n        color: \"#F97316\",\n        bgColor: \"bg-orange-500\",\n        textColor: \"text-orange-600\",\n        bgLight: \"bg-orange-50\",\n        icon: \"BarChart2\"\n    },\n    \"volunteer-activity\": {\n        label: \"見守り活動\",\n        color: \"#22C55E\",\n        bgColor: \"bg-green-500\",\n        textColor: \"text-green-600\",\n        bgLight: \"bg-green-50\",\n        icon: \"Users\"\n    },\n    \"safety-tips\": {\n        label: \"安全対策\",\n        color: \"#3B82F6\",\n        bgColor: \"bg-blue-500\",\n        textColor: \"text-blue-600\",\n        bgLight: \"bg-blue-50\",\n        icon: \"Shield\"\n    },\n    \"policy-update\": {\n        label: \"施策・制度\",\n        color: \"#8B5CF6\",\n        bgColor: \"bg-purple-500\",\n        textColor: \"text-purple-600\",\n        bgLight: \"bg-purple-50\",\n        icon: \"FileText\"\n    }\n};\n// 記事データ（実際のコンテンツファイルから読み込んだもの）\nconst ARTICLES = [\n    {\n        id: \"2026-02-06-chikushino-accident\",\n        slug: \"chikushino-accident\",\n        title: \"対策済み通学路でも事故発生 - 福岡・筑紫野市の教訓\",\n        excerpt: \"2025年5月、福岡県筑紫野市で「危険箇所」としてリストアップされ対策が講じられていた通学路で、下校中の小学生が車にはねられる事故が発生しました。ハード対策だけでは完全な安全を確保できないことを示す事例として、私たちに何ができるかを考えます。\",\n        category: \"accident-news\",\n        categoryLabel: \"事故ニュース\",\n        categoryColor: \"#EF4444\",\n        categoryIcon: \"AlertTriangle\",\n        publishedDate: \"2026-02-06\",\n        tags: [\n            \"通学路事故\",\n            \"小学生\",\n            \"交通事故\",\n            \"危険箇所\",\n            \"福岡県\"\n        ],\n        thumbnailUrl: \"/images/safe-magazine/thumbnails/chikushino-accident.png\",\n        contentImages: [\n            {\n                id: \"hard-vs-soft\",\n                url: \"/images/safe-magazine/articles/chikushino-accident/hard-vs-soft.png\",\n                description: \"ハード対策とソフト対策の比較\"\n            }\n        ],\n        keyPoints: [\n            \"危険箇所としてリストアップされ対策済みだった通学路でも事故は発生した\",\n            \"ハード対策（物理的整備）だけでは、人的要因による事故を完全に防ぐことはできない\",\n            \"見守り活動や安全教育などのソフト対策との両輪で、通学路の安全を守ることが重要\"\n        ],\n        sources: [\n            \"西日本新聞「筑紫野市で下校中の小学生の列に車突っ込む」（2025年5月19日）\",\n            \"NHK福岡放送局「筑紫野市で小学生4人搬送」（2025年5月19日）\",\n            \"KBC九州朝日放送「筑紫野市の通学路事故」（2025年5月19日）\"\n        ],\n        content: `### 事故の概要\n\n2025年5月19日午後3時半頃、福岡県筑紫野市針摺西の市道で、74歳の女性が運転する軽乗用車が下校中の小学生の列に突っ込む事故が発生しました。この事故で9歳の男児4人と運転手の女性が病院に搬送され、男児1人と女性が骨折。幸いにも全員命に別条はありませんでした。\n\n### 対策済みの「危険箇所」だった現場\n\n事故現場は、以前から「危険な通学路」としてリストアップされており、路面の舗装色を変えるなど視覚的な対策が講じられていた場所でした。にもかかわらず事故が起きたことは、物理的な安全対策（ハード対策）の限界を示しています。\n\n### なぜ対策済みでも事故は起きるのか\n\n通学路の安全対策には、大きく分けて以下の2種類があります。\n\n**ハード対策**（物理的な環境整備）\n- 歩道の整備・拡幅\n- ガードレール・防護柵の設置\n- 路面カラー舗装\n- 信号機・横断歩道の設置\n- ゾーン30の導入\n\n**ソフト対策**（人的・教育的な取り組み）\n- 見守り活動の強化\n- 交通安全教育の実施\n- ドライバーへの啓発\n- 登下校時間帯の通行制限\n\n今回の事故は、ハード対策だけでは防ぎきれない事故があることを示しています。運転者の注意力や判断ミス、体調不良など、人的要因による事故はハード対策だけでは完全に防げません。\n\n### 私たちにできること\n\nこの事故から学べる教訓として、以下のことが挙げられます。\n\n1. **「対策済み=安全」ではない意識を持つ**\n   保護者や地域の方は、対策済みの場所でも油断せず、見守りの目を向けることが大切です。\n\n2. **子どもへの継続的な安全教育**\n   「青信号でも左右を確認する」「車が止まってから渡る」など、基本的な交通ルールを繰り返し教えましょう。\n\n3. **見守り活動への参加**\n   通学路での見守り活動は、ドライバーへの注意喚起効果もあります。短時間でも参加することで地域全体の安全性が高まります。\n\n4. **危険な運転への声かけ**\n   身近に高齢ドライバーがいる場合、定期的な健康チェックや運転技術の確認を促すことも重要です。`\n    },\n    {\n        id: \"2026-02-06-school-route-safety-statistics\",\n        slug: \"school-route-safety-statistics\",\n        title: \"通学路の安全対策91%完了、でも小1の事故リスクは6年生の2.9倍\",\n        excerpt: \"国土交通省の発表によると、全国の通学路危険箇所の約91%で安全対策が完了しました。しかし、警視庁の統計では小学1年生の交通事故リスクは依然として高いまま。データから見える通学路安全の現状と、特に入学間もない子どもたちを守るための対策を解説します。\",\n        category: \"danger-ranking\",\n        categoryLabel: \"危険度情報\",\n        categoryColor: \"#F97316\",\n        categoryIcon: \"BarChart2\",\n        publishedDate: \"2026-02-06\",\n        tags: [\n            \"統計\",\n            \"小学生事故\",\n            \"1年生\",\n            \"交通安全\",\n            \"通学路\",\n            \"入学準備\"\n        ],\n        thumbnailUrl: \"/images/safe-magazine/thumbnails/school-route-safety-statistics.png\",\n        contentImages: [\n            {\n                id: \"grade-comparison\",\n                url: \"/images/safe-magazine/articles/school-route-safety-statistics/grade-comparison.png\",\n                description: \"学年別事故リスク比較\"\n            },\n            {\n                id: \"progress-circle\",\n                url: \"/images/safe-magazine/articles/school-route-safety-statistics/progress-circle.png\",\n                description: \"91%完了の進捗\"\n            }\n        ],\n        keyPoints: [\n            \"全国の通学路危険箇所の約91%で安全対策が完了（2023年12月末時点）\",\n            \"しかし小学1年生の交通事故リスクは6年生の約2.9倍と依然として高い\",\n            \"入学前後の親子での通学路確認と、地域の見守り活動が事故防止の鍵\"\n        ],\n        sources: [\n            \"警視庁「令和7年上半期 小学生の交通人身事故発生状況」（2025年7月10日）\",\n            \"国土交通省「通学路の交通安全の確保に向けた取組」（2023年12月末時点）\",\n            \"一般社団法人日本損害保険協会「全国交通事故多発交差点マップ」（2025年9月更新）\"\n        ],\n        content: `### 国の通学路安全対策は着実に進展\n\n2021年6月、千葉県八街市で下校中の小学生5人がトラックにはねられ死傷するという痛ましい事故が発生しました。この事故を受けて政府は全国の通学路の一斉点検を実施し、76,404箇所が「対策が必要な危険箇所」としてリストアップされました。\n\n国土交通省の発表（令和5年12月末時点）によると、対策必要箇所72,568箇所のうち、66,203箇所（約91%）で安全対策が完了しています。\n\n**主な対策内容**\n- 歩道の整備・拡幅\n- 路肩のカラー舗装（グリーンベルト）\n- 防護柵・ガードレールの設置\n- 信号機の新設・改良\n- ゾーン30（生活道路の30km/h規制区域）の導入\n\n### それでも残る小学1年生の高い事故リスク\n\n対策が進む一方で、警視庁が2025年7月に公表した統計データは、見過ごせない事実を示しています。\n\n**小学生の交通事故（歩行中）の特徴**\n\n| 学年 | 死者・重傷者リスク |\n|------|------------------|\n| 1年生 | 最も高い |\n| 6年生 | 1年生の約1/2.9 |\n\nつまり、**小学1年生の死者・重傷者数は6年生の約2.9倍**という深刻なデータが出ています。\n\n### なぜ1年生の事故リスクが高いのか\n\n小学1年生の事故リスクが高い理由には、以下のような要因が考えられます。\n\n**1. 環境の大きな変化**\n- 保育園・幼稚園では送迎が当たり前だったのに、急に一人で通学\n- 通学路が長くなる（平均1km以上の通学も珍しくない）\n- 初めての道、初めての交差点が多い\n\n**2. 身体的・認知的な発達段階**\n- 体が小さく、ドライバーから見えにくい\n- 視野が狭く、周辺の危険に気づきにくい\n- 複数の情報を同時に処理するのが難しい\n- 「危ない」と思ってもすぐに止まれない\n\n**3. 注意力の特性**\n- 興味があるものに集中すると周りが見えなくなる\n- 友達との会話に夢中になりやすい\n- 時間の感覚がまだ発達途上\n\n### 入学シーズンに向けた具体的な対策\n\n4月の入学シーズンを前に、保護者や地域でできる対策をまとめました。\n\n**入学前（3月中）に行いたいこと**\n\n1. **通学路の下見を親子で行う**\n   実際に歩いて危険な場所を確認し、「ここでは必ず止まろうね」と具体的に教える\n\n2. **時間に余裕を持った登校練習**\n   焦ると注意力が低下します。余裕を持って歩けるスケジュールを把握しておく\n\n3. **「とまる・みる・まつ」の徹底**\n   横断歩道では「止まる」「左右を見る」「車が止まるまで待つ」を繰り返し練習\n\n**入学後に継続したいこと**\n\n1. **最初の1〜2週間は付き添い登校**\n   可能であれば、子どもが慣れるまで一緒に歩く\n\n2. **帰宅後の振り返り**\n   「今日、危なかったことはあった？」と声かけを習慣に\n\n3. **見守り活動への参加**\n   登下校の時間帯に通学路に立つ大人が増えることで、子どもの安全が高まる\n\n### 交差点事故マップの活用\n\n日本損害保険協会が公表している「全国交通事故多発交差点マップ」は、2023年以降、各交差点から最も近い小学校の情報も掲載されるようになりました。お住まいの地域の交差点がマップに載っていないか、ぜひ確認してみてください。`\n    },\n    {\n        id: \"2026-02-06-nagara-mimamori-guide\",\n        slug: \"nagara-mimamori-guide\",\n        title: \"見守り活動の新しいカタチ「ながら見守り」のすすめ\",\n        excerpt: \"「見守り活動に参加したいけど時間がない」「毎日は難しい」。そんな方におすすめなのが「ながら見守り」です。散歩やジョギング、買い物のついでにできる新しい見守りスタイルを、文部科学省も推奨しています。担い手不足の解消と、誰でも気軽に参加できる方法を紹介します。\",\n        category: \"volunteer-activity\",\n        categoryLabel: \"見守り活動\",\n        categoryColor: \"#22C55E\",\n        categoryIcon: \"Users\",\n        publishedDate: \"2026-02-06\",\n        tags: [\n            \"見守り\",\n            \"ボランティア\",\n            \"ながら見守り\",\n            \"防犯\",\n            \"子ども110番\",\n            \"地域安全\"\n        ],\n        thumbnailUrl: \"/images/safe-magazine/thumbnails/nagara-mimamori-guide.png\",\n        contentImages: [\n            {\n                id: \"nagara-examples\",\n                url: \"/images/safe-magazine/articles/nagara-mimamori-guide/nagara-examples.png\",\n                description: \"ながら見守りの例\"\n            },\n            {\n                id: \"hachimitsu-jiman\",\n                url: \"/images/safe-magazine/articles/nagara-mimamori-guide/hachimitsu-jiman.png\",\n                description: \"防犯合言葉「はちみつじまん」\"\n            }\n        ],\n        keyPoints: [\n            \"見守りボランティアの高齢化・担い手不足が全国で深刻化している\",\n            \"「ながら見守り」は散歩や買い物のついでにできる新しい見守りスタイル\",\n            \"毎日でなくても、週1回からでも参加でき、地域全体の「見守る目」を増やす効果がある\"\n        ],\n        sources: [\n            \"文部科学省「やってみよう！登下校見守り活動ハンドブック」\",\n            \"文部科学省「登下校防犯プラン」\",\n            \"神戸新聞「見守りボランティアの高齢化・担い手不足」（2021年12月）\",\n            \"セコム「子どもの防犯と安全教育」\"\n        ],\n        content: `### 深刻化する見守りボランティアの担い手不足\n\n全国の小学校通学路で活動する見守りボランティア（スクールガード）は、地域の子どもたちの安全を支える大切な存在です。しかし今、深刻な問題に直面しています。\n\n**見守り活動の現状**\n- 一部地域では参加者の平均年齢が80歳を超えている\n- 日々の活動参加者が数年前の半分以下になった地域も\n- 高齢化と体力的な問題から引退する人が増加\n- 新たな担い手がなかなか見つからない\n\n従来の見守り活動は「毎朝・毎夕、決まった場所に立つ」というスタイルが主流でした。しかし、共働き世帯の増加や働き方の多様化により、このスタイルでの参加が難しい人が増えています。\n\n### 「ながら見守り」という新しい選択肢\n\n文部科学省は「やってみよう！登下校見守り活動ハンドブック」の中で、従来型の見守りだけでなく、「ながら見守り」という新しい参加形態を推奨しています。\n\n**「ながら見守り」とは**\n\n日常生活の行動をしながら、自然な形で子どもたちの安全を見守る活動のことです。\n\n**ながら見守りの例**\n- 朝の散歩のついでに通学路を歩く\n- 犬の散歩で登下校の時間帯に外に出る\n- ジョギングのコースに通学路を組み込む\n- 買い物帰りの時間を登下校時間に合わせる\n- 庭の水やりや掃除を登校時間帯に行う\n- 通勤の徒歩部分で子どもたちを見かけたら挨拶する\n\n### ながら見守りの効果\n\n「そんな気軽な活動で効果があるの？」と思われるかもしれません。しかし、ながら見守りには確かな効果があります。\n\n**1. 地域に「見守る目」を増やす**\n特別な装備やスキルは不要。普段着のまま、日常の延長で参加できるので、参加者が増えやすく、結果として地域全体の「見守る目」が増えます。\n\n**2. 不審者への抑止効果**\n不審者による声かけ事案のほとんどは、子どもがひとりでいる時に発生しています。大人の目が増えることで、不審者が近づきにくい環境が生まれます。\n\n**3. ドライバーへの注意喚起**\n通学路を歩く大人がいることで、ドライバーは「この辺りは子どもがいるかもしれない」と注意を払うようになります。\n\n**4. 子どもたちの安心感**\n「知っている大人がいる」という安心感は、子どもたちの精神的な支えになります。\n\n### 今日から始められる「ながら見守り」の始め方\n\n**ステップ1: まずは時間を知る**\nお住まいの地域の小学校の登下校時間を確認しましょう。一般的には以下の時間帯です。\n- 登校: 午前7時30分〜8時15分頃\n- 下校: 午後2時30分〜4時30分頃（学年・曜日により異なる）\n\n**ステップ2: 日常の行動を見直す**\n「登下校の時間帯に外出する用事」を探してみましょう。\n- 朝刊を取りに行くついでに\n- ゴミ出しのついでに\n- 花の水やりのついでに\n\n**ステップ3: 挨拶から始める**\n特別なことをする必要はありません。子どもたちに「おはよう」「いってらっしゃい」「おかえり」と声をかけるだけで十分です。\n\n**ステップ4: 続けやすいペースで**\n毎日でなくても構いません。週に1〜2回でも、月に数回でも、無理のないペースで続けることが大切です。\n\n### 「子ども110番の家」との連携\n\n文部科学省の「登下校防犯プラン」では、教育委員会・学校と「子ども110番の家」との連携強化も推進されています。\n\n「子ども110番の家」とは、子どもが危険を感じた時に駆け込める場所として登録された民家や店舗のこと。ながら見守り活動中に「子ども110番の家」の場所を確認しておくと、いざという時に子どもを誘導できます。\n\n### 子どもに教えたい防犯の合言葉\n\n見守り活動と合わせて、子どもたち自身が身を守る力をつけることも大切です。「はちみつじまん」という防犯合言葉を覚えておきましょう。\n\n- **は**：話しかけてくる人に注意\n- **ち**：近づいてくる人に注意\n- **み**：見つめてくる人に注意\n- **つ**：ついてくる人に注意\n- **じ**：車に乗せようとする人に注意\n- **ま**：待っている人に注意\n- **ん**：？と思ったらすぐ逃げる`\n    },\n    {\n        id: \"2026-03-15-bicycle-blue-ticket\",\n        slug: \"bicycle-blue-ticket\",\n        title: \"【4月から施行】自転車も「青切符」の対象に——中高生の通学に何が変わる？\",\n        excerpt: \"2026年4月1日から、自転車の交通違反に「青切符（交通反則通告制度）」が適用されます。通学で自転車を使う中学生・高校生にも直接関係する制度変更です。保護者として知っておくべきポイントをまとめました。\",\n        category: \"policy-update\",\n        categoryLabel: \"施策・制度\",\n        categoryColor: \"#8B5CF6\",\n        categoryIcon: \"FileText\",\n        publishedDate: \"2026-03-15\",\n        tags: [\n            \"自転車\",\n            \"青切符\",\n            \"交通違反\",\n            \"通学\",\n            \"中高生\",\n            \"道路交通法改正\"\n        ],\n        thumbnailUrl: \"/images/safe-magazine/thumbnails/bicycle-blue-ticket.png\",\n        contentImages: [\n            {\n                id: \"violation-fines\",\n                url: \"/images/safe-magazine/articles/bicycle-blue-ticket/violation-fines.png\",\n                description: \"主な違反行為と反則金一覧\"\n            },\n            {\n                id: \"age-target\",\n                url: \"/images/safe-magazine/articles/bicycle-blue-ticket/age-target.png\",\n                description: \"対象年齢（16歳以上）の説明図\"\n            }\n        ],\n        keyPoints: [\n            \"2026年4月1日から、16歳以上の自転車違反に青切符が適用開始\",\n            \"信号無視・一時不停止・ながらスマホなど113項目が対象\",\n            \"新学期前に、ヘルメット着用・一時停止・スマホ禁止を家庭で確認しよう\"\n        ],\n        sources: [\n            \"政府広報オンライン「2026年4月から自転車の交通違反に「青切符」を導入！」\",\n            \"JAF Mate Online「2026年自転車法改正！青切符導入で何が変わる？」（2026年2月9日）\",\n            \"警察庁「自転車の交通違反に対する反則金制度の導入について」\"\n        ],\n        content: `### 青切符とは何か\n\n「青切符」とは、交通反則通告制度に基づく処理方法のことです。違反が発覚した際に反則金を納めることで、刑事手続き（罰金・前科）を経ずに処理できる仕組みです。これまでは自動車・原付バイクのみが対象でしたが、2024年の道路交通法改正により、2026年4月から自転車も対象に加わります。\n\n### 対象となる違反行為（主なもの）\n\n青切符の対象となる違反は計113項目あります。通学中に起きやすい代表的な違反として以下が挙げられます。\n\n- **信号無視**（3,000円）\n- **一時不停止**（3,000円）\n- **左側通行義務違反**（逆走）（3,000円）\n- **ながらスマホ**（6,000円）\n- **並進**（2,000円）\n- **夜間の無灯火**（3,000円）\n- **歩道通行時の歩行者妨害**（2,000円）\n\n### 誰が対象になるのか\n\n16歳以上の自転車利用者が対象です。学年ではなく年齢基準なので、**高校生でも16歳になるまでは対象外**、逆に16歳になっていれば対象になります。\n\n### 赤切符との違い\n\n| | 青切符（新制度） | 赤切符（従来） |\n|---|---|---|\n| 対象 | 軽微な違反 | 重大な違反・悪質な違反 |\n| 処理 | 反則金を納付 | 刑事手続き（前科あり） |\n| 手続き | 比較的簡易 | 裁判所での手続きが必要 |\n\n悪質な違反（飲酒運転、妨害運転、重大事故につながる違反など）は引き続き赤切符の対象となり、刑事責任を問われる可能性があります。\n\n### 保護者として確認したいこと\n\n新学期が始まる前に、お子さんと自転車通学のルールについて改めて確認しましょう。\n\n**1. ヘルメット着用の徹底**\n2023年4月から自転車乗車時のヘルメット着用が努力義務化されています。万が一の事故時の安全確保のためにも、習慣づけを。\n\n**2. スマートフォンを使いながらの運転は絶対にしない**\n「ながらスマホ」は最も高い反則金（6,000円）が科される違反です。音楽を聴く場合も、周囲の音や警音器が聞こえない状態にならないよう、住んでいる地域の交通ルールを確認しておきましょう。\n\n**3. 通学路の交差点・踏切での一時停止**\n「いつも通っているから大丈夫」という慣れからの違反が多いのがこのケースです。一時停止標識のある場所では必ず停車確認する習慣を確認しましょう。\n\n**4. 左側通行の徹底**\n自転車は車道の左側を通行するのが原則です。右側逆走は車との正面衝突リスクが高く、最も危険な違反のひとつです。\n\n### 学校での対応\n\n多くの中学・高校では、新学期の交通安全指導の中でこの制度変更について説明が行われます。学校からの配布物や連絡に注意し、お子さんへの声かけに活用してください。`\n    },\n    {\n        id: \"2026-03-15-30kmh-speed-limit\",\n        slug: \"30kmh-speed-limit\",\n        title: \"【2026年9月施行】住宅街・通学路の速度制限が30km/hへ——何が変わるの？\",\n        excerpt: \"2026年9月1日から、住宅街や生活道路の法定速度が現行の60km/hから30km/hに引き下げられます。通学路を含む多くの住宅街の道路がこの恩恵を受けます。「ゾーン30」とは何が違うのか、保護者目線でわかりやすく解説します。\",\n        category: \"policy-update\",\n        categoryLabel: \"施策・制度\",\n        categoryColor: \"#8B5CF6\",\n        categoryIcon: \"FileText\",\n        publishedDate: \"2026-03-15\",\n        tags: [\n            \"法定速度\",\n            \"30km/h\",\n            \"生活道路\",\n            \"通学路\",\n            \"道路交通法改正\",\n            \"ゾーン30\"\n        ],\n        thumbnailUrl: \"/images/safe-magazine/thumbnails/30kmh-speed-limit.png\",\n        contentImages: [\n            {\n                id: \"fatality-rate\",\n                url: \"/images/safe-magazine/articles/30kmh-speed-limit/fatality-rate.png\",\n                description: \"衝突速度別の歩行者致死率比較\"\n            },\n            {\n                id: \"zone30-comparison\",\n                url: \"/images/safe-magazine/articles/30kmh-speed-limit/zone30-comparison.png\",\n                description: \"ゾーン30と今回の法改正の違い\"\n            }\n        ],\n        keyPoints: [\n            \"2026年9月1日から、速度標識のない生活道路の法定速度が60km/h→30km/hへ\",\n            \"通学路を含む住宅街の多くの道路が対象\",\n            \"速度制限が下がっても、子どもへの安全教育は引き続き大切\"\n        ],\n        sources: [\n            \"JAF交通安全トレーニングコラム「2026年法改正｜法定速度や自転車に絡む交通ルールの変更点を紹介」\",\n            \"道路交通法改正解説「生活道路30km/h制限の全解説」\",\n            \"警察庁「ゾーン30プラスの推進について」\"\n        ],\n        content: `### なぜ今、速度制限が変わるのか\n\n現在の日本の法定速度は、速度標識がない一般道は一律60km/hです。しかし子どもが歩く住宅街の細い道も、幹線道路も、標識がなければ同じ60km/hが適用されているのが現状でした。\n\n歩行者がはねられたときの致死率は、衝突時の速度によって大きく変わります。\n- **30km/h以下**: 致死率 約10%\n- **50km/h**: 致死率 約75%\n- **60km/h**: 致死率 約95%以上\n\n欧州では多くの国が生活道路を30km/h以下に規制しており、今回の改正はこうした国際基準に合わせる形での見直しです。\n\n### 対象となる道路\n\n今回の改正で30km/hに引き下げられるのは「速度標識がない生活道路・住宅街の道路」です。具体的には以下のような場所が対象です。\n\n- 住宅街の細い生活道路\n- 通学路に指定されている住宅街の道路\n- 商店街の裏通りなど\n\n一方、**幹線道路や国道・県道など、速度標識が設置されている道路は対象外**です。\n\n### 「ゾーン30」「ゾーン30プラス」との違い\n\n| | ゾーン30（従来） | 2026年9月の法改正 |\n|---|---|---|\n| 導入方法 | 各自治体が申請・整備 | 法律で一律に適用 |\n| 範囲 | 申請した区域のみ | 全国の無標識生活道路 |\n| 物理的対策 | ハンプ・狭窄など整備あり | 速度規制のみ |\n\n今回の法改正により、ゾーン30の整備が追いついていない地域でも、法的に30km/h制限が適用されることになります。\n\n### 子どもへの影響・保護者として伝えること\n\nこの法改正により通学路の安全性は向上しますが、それでも完全な安全が保証されるわけではありません。引き続き以下の点を子どもに伝えましょう。\n\n1. **速度制限が変わっても、車は来ると思って行動する**\n   法律が変わっても全員が守るとは限りません。横断歩道でも左右確認を怠らないように伝えましょう。\n\n2. **飛び出しは絶対にしない**\n   30km/hの車でも、急な飛び出しには対応できません。\n\n3. **歩行者も交通ルールを守る意識を**\n   信号を守る、横断歩道以外では渡らないなど、基本的なルールの習慣化を続けましょう。`\n    },\n    {\n        id: \"2026-03-15-ai-camera-kakogawa\",\n        slug: \"ai-camera-kakogawa\",\n        title: \"高度化カメラが通学路を支援——加古川市の「見守りカメラ」施策に学ぶ\",\n        excerpt: \"兵庫県加古川市は、見守りカメラ約1,500ヵ所に加え、高度化見守りカメラ150台を整備しています。高度化カメラでは異常音検知や車両接近検知などを行い、2017年から2023年にかけて市内の刑法犯認知件数は約4割減少しました。\",\n        category: \"safety-tips\",\n        categoryLabel: \"安全対策\",\n        categoryColor: \"#3B82F6\",\n        categoryIcon: \"Shield\",\n        publishedDate: \"2026-03-15\",\n        tags: [\n            \"AIカメラ\",\n            \"防犯カメラ\",\n            \"加古川市\",\n            \"テクノロジー\",\n            \"見守り\",\n            \"通学路安全\"\n        ],\n        thumbnailUrl: \"/images/safe-magazine/thumbnails/ai-camera-kakogawa.png\",\n        contentImages: [\n            {\n                id: \"crime-reduction\",\n                url: \"/images/safe-magazine/articles/ai-camera-kakogawa/crime-reduction.png\",\n                description: \"刑法犯認知件数の推移（6年で4割減）\"\n            },\n            {\n                id: \"ai-features\",\n                url: \"/images/safe-magazine/articles/ai-camera-kakogawa/ai-features.png\",\n                description: \"高度化見守りカメラの主な機能\"\n            }\n        ],\n        keyPoints: [\n            \"加古川市は見守りカメラ約1,500ヵ所と、高度化見守りカメラ150台を整備\",\n            \"異常音検知・車両接近検知などの高度機能は150台の高度化見守りカメラで運用\",\n            \"6年間で刑法犯認知件数が約40%減少という実績\"\n        ],\n        sources: [\n            \"加古川市公式サイト「見守りカメラ」\",\n            \"加古川市公式サイト「見守りサービス」\",\n            \"アルコム「通学路の防犯カメラに関するアンケート調査」（2025年7月）\"\n        ],\n        content: `### 約1,500ヵ所の見守りカメラと150台の高度化カメラ\n\n加古川市は、見守りカメラ約1,500ヵ所に加え、高度化見守りカメラ150台、防犯カメラ3台を運用しています。通学路や学校周辺を含む地域の見守り網を広げつつ、必要な場所には検知機能を強化したカメラを配置しているのが特徴です。\n\n### 高度化見守りカメラでは何ができるのか\n\n市内のすべての見守りカメラが同じ機能を持つわけではありません。異常音検知や車両接近検知などの機能は、150台の高度化見守りカメラで提供されています。\n\n**異常音検知**\n悲鳴や助けを求める声など、異常な音声を検知すると自動でアラートを発します。夜間や見通しの悪い場所での緊急事態にも対応できます。\n\n**車両接近検知**\n車両が歩行者（特に子ども）に危険な距離まで接近した場合、付近のスピーカーと回転灯が作動して警告を発します。交差点や横断歩道付近での事故防止に効果を発揮します。\n\n**リアルタイム監視との連携**\n異常検知時には担当部署へ即時通知が届く仕組みにより、人が常時監視しなくても迅速な対応が可能です。\n\n### 6年間で刑法犯4割減という結果\n\n加古川市の公開資料によると、見守りカメラの整備が進んだ2017年から2023年にかけて、市内の刑法犯認知件数は約3,000件から1,752件へ減少しました。単純にカメラだけの効果とは言い切れないものの、地域見守りとテクノロジーを組み合わせた施策の成果として紹介されています。\n\nカメラが実際に犯罪を抑止した事例として、不審者がカメラに気づいて犯行をやめたケースや、事後の映像解析により検挙につながった事例も報告されています。\n\n### 「見守り疲れ」を補うテクノロジー\n\n加古川市の取り組みは、人の目とAIの目を組み合わせた「ハイブリッド見守り」の先進事例として全国の自治体から注目されています。ただし、地域コミュニティとの連携、子どもへの安全教育、そしてテクノロジーの三位一体が重要です。\n\n### 2025年のアンケート調査でも防犯カメラへの期待が高い\n\n2025年に実施された調査では、保護者の約8割が「通学路にもっと防犯カメラを設置すべき」と回答しています（アルコム調べ）。子どもの安全を守る手段として、テクノロジーへの期待は確実に高まっています。\n\n### 保護者として知っておきたいこと\n\n- お住まいの市区町村で見守りカメラが設置されている場所を確認しておきましょう\n- カメラが設置されている場所でも、子どもに「知らない人についていかない」「助けを求める」などの基本的な安全行動を教えることが引き続き大切です\n- 地域の防犯情報や見守りマップは、自治体や警察署のウェブサイトで公開されていることが多いです`\n    },\n    {\n        id: \"2026-03-15-suspicious-person-statistics\",\n        slug: \"suspicious-person-statistics\",\n        title: \"「声かけ」は15時台が最多——公開統計から見る下校時間帯の不審者対策\",\n        excerpt: \"警察庁が2025年3月に公表した令和6年の統計データと、千葉県警察の公開グラフから、声かけ事案が下校時間帯、とくに15時台に集中している傾向を解説します。\",\n        category: \"safety-tips\",\n        categoryLabel: \"安全対策\",\n        categoryColor: \"#3B82F6\",\n        categoryIcon: \"Shield\",\n        publishedDate: \"2026-03-15\",\n        tags: [\n            \"不審者\",\n            \"声かけ事案\",\n            \"防犯\",\n            \"下校時間\",\n            \"統計\",\n            \"はちみつじまん\"\n        ],\n        thumbnailUrl: \"/images/safe-magazine/thumbnails/suspicious-person-statistics.png\",\n        contentImages: [\n            {\n                id: \"time-chart\",\n                url: \"/images/safe-magazine/articles/suspicious-person-statistics/time-chart.png\",\n                description: \"声かけ事案の発生時間帯グラフ\"\n            }\n        ],\n        keyPoints: [\n            \"千葉県警の公開グラフでは15時台が23.9%で最多\",\n            \"14時台・16時台も高く、下校時間帯への集中が見て取れる\",\n            \"「複数で帰る」「防犯ブザーを持つ」「子ども110番の家を知っている」の3点が基本対策\"\n        ],\n        sources: [\n            \"警察庁「令和6年における少年非行及び子供の性被害の状況について」（2025年3月3日公表）\",\n            \"千葉県警察「子供を犯罪から守りましょう」\",\n            \"文部科学省「登下校防犯プラン」\",\n            \"セコム「声かけ事案とは」（2025年11月）\"\n        ],\n        content: `### 最新データから見る声かけ事案の実態\n\n警察庁は2025年3月3日、「令和6年における少年非行及び子供の性被害の状況について」を公表しました。このデータによると、SNSを介した子ども（18歳未満）の犯罪被害は1,486人（前年比179人減）と減少傾向にある一方、小学生については136人とほぼ横ばいが続いています。\n\n### 声かけ事案はいつ起きているのか\n\n千葉県警察が公開している子ども向け防犯ページの時間帯別グラフでは、発生時間帯の分布は以下のとおりです。\n\n1. **15時台: 23.9%**（最多）\n2. **16時台: 15.7%**\n3. **14時台: 14.1%**\n\n→ 下校時間帯（午後2〜5時）に集中していることがわかります\n\n### 子どもに伝えたい3つの行動\n\n**1. 一人で歩かない**\n声かけ事案の大半は子どもが一人のときに発生します。友達と一緒に帰る、下校時間をそろえるなど、できるだけ複数で行動するよう習慣づけましょう。\n\n**2. 「はちみつじまん」の合言葉を覚える**\n\n| 文字 | 意味 |\n|------|------|\n| は | 走って逃げる |\n| ち | 近寄らない |\n| み | 見知らぬ人についていかない |\n| つ | つれていかれそうになったら大声で叫ぶ |\n| じ | 自分の身は自分で守る |\n| ま | まわりの大人に助けを求める |\n| ん | 防犯ブザーを鳴らす |\n\n**3. 「子ども110番の家」の場所を覚えておく**\n緊急時に逃げ込める「子ども110番の家」（黄色い三角のプレートが目印）の場所を、通学路沿いで親子一緒に確認しておきましょう。\n\n### 保護者ができること\n\n- **下校時間帯（午後2〜5時）に短時間でも外に出る**\n  「ながら見守り」として、この時間帯に買い物や犬の散歩などで通学路近辺を歩くだけでも抑止効果があります。\n\n- **防犯ブザーの定期チェック**\n  ランドセルに付いている防犯ブザーが正常に鳴るか、定期的に確認しましょう。電池切れで鳴らなかったという事例も報告されています。\n\n- **学校・警察の不審者情報を確認する**\n  多くの自治体では、不審者情報をメールやアプリで配信しています。登録しておくことで地域の状況を把握できます。`\n    }\n];\n// 記事をスラッグで取得\nfunction getArticleBySlug(slug) {\n    return ARTICLES.find((article)=>article.slug === slug);\n}\n// すべての記事を取得\nfunction getAllArticles() {\n    return ARTICLES.sort((a, b)=>new Date(b.publishedDate).getTime() - new Date(a.publishedDate).getTime());\n}\n// カテゴリで記事をフィルタ\nfunction getArticlesByCategory(category) {\n    return ARTICLES.filter((article)=>article.category === category);\n}\n// 日付をフォーマット\nfunction formatDate(dateString) {\n    const date = new Date(dateString);\n    return `${date.getFullYear()}.${String(date.getMonth() + 1).padStart(2, '0')}.${String(date.getDate()).padStart(2, '0')}`;\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/safe-magazine.ts\n");

